const staticData = $getWorkflowStaticData('global');

const supabaseUrl = String($env.SUPABASE_URL || $env.NEXT_PUBLIC_SUPABASE_URL || '').trim();
const supabaseServiceRoleKey = String($env.SUPABASE_SERVICE_ROLE_KEY || '').trim();

if (!supabaseUrl) {
  throw new Error('Missing SUPABASE_URL (or NEXT_PUBLIC_SUPABASE_URL fallback)');
}

if (!/^https?:\/\//i.test(supabaseUrl)) {
  throw new Error('Invalid SUPABASE_URL format. Expected https://<project>.supabase.co');
}

if (!supabaseServiceRoleKey || supabaseServiceRoleKey.length < 20 || !supabaseServiceRoleKey.startsWith('sb_secret_')) {
  throw new Error('Invalid SUPABASE_SERVICE_ROLE_KEY. Set a valid sb_secret_* key and remove duplicates');
}

const env = {
  SUPABASE_URL: supabaseUrl,
  SUPABASE_SERVICE_ROLE_KEY: supabaseServiceRoleKey,
  ESIOS_API_TOKEN: $env.ESIOS_API_TOKEN || '',
  GEO_SOURCE_CSV_URL: $env.GEO_SOURCE_CSV_URL || '',
  IBI_ICIO_JSON_URL: $env.IBI_ICIO_JSON_URL || '',
  COMPATIBILIDAD_CSV_URL: $env.COMPATIBILIDAD_CSV_URL || '',
  PVGIS_BASE_URL: $env.PVGIS_BASE_URL || 'https://re.jrc.ec.europa.eu/api/v5_2',
  BATCH_SIZE: parseInt($env.BATCH_SIZE || '50', 10),
  DRY_RUN: ($env.DRY_RUN || 'false') === 'true',
  STRICT_PROD: ($env.STRICT_PROD || 'true') === 'true',
  AI_TO_STAGING_ONLY: ($env.AI_TO_STAGING_ONLY || 'true') === 'true',
  AI_BASE_URL: $env.AI_BASE_URL || 'https://api.openai.com/v1/chat/completions',
  AI_API_KEY: $env.AI_API_KEY || '',
  AI_MODEL: $env.AI_MODEL || 'gpt-4o-mini'
};

staticData.strictAlerts = [];
staticData.deadLetters = [];

const runId = `run_${Date.now()}`;
console.log(JSON.stringify({
  stage: 'INIT',
  runId,
  env: {
    ...env,
    SUPABASE_SERVICE_ROLE_KEY: '***',
    ESIOS_API_TOKEN: env.ESIOS_API_TOKEN ? '***' : '',
    AI_API_KEY: env.AI_API_KEY ? '***' : ''
  }
}));

return [{ json: { ...env, runId, startedAt: new Date().toISOString() } }];

