// GEO â€“ Parse CSV
// El CSV tiene cabecera: "Comunidad","Provincia","Municipio","PoblaciÃ³n","Latitud","Longitud"
// Cada lÃ­nea empieza con '+' (artefacto del repo)
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
function getCtx() { try { return $('INIT â€“ Env & Config').first().json; } catch(_) { return {}; } }
const ctx = getCtx();

// Obtener el texto crudo â€“ n8n con responseFormat=text lo pone en item.json como string
const item = $input.first();
let raw = '';
if (typeof item.json === 'string') {
  raw = item.json;
} else if (typeof item.json?.data === 'string') {
  raw = item.json.data;
} else if (typeof item.json?.body === 'string') {
  raw = item.json.body;
} else {
  raw = JSON.stringify(item.json);
}

console.log('GEO_RAW_LENGTH:', raw.length);
console.log('GEO_FIRST_LINE:', raw.split('\n')[0]);

function slugify(t) {
  return (t||'').toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9\s-]/g, '').trim().replace(/\s+/g, '-');
}

const parseNum = v => { const n = parseFloat(String(v||'').replace(',','.')); return isFinite(n) ? n : null; };
const parseInt2 = v => { const n = parseInt(v, 10); return isFinite(n) ? n : null; };

// Detectar separador
function detectSep(line) {
  const clean = line.replace(/"/g, '');
  const sc = { ',':(clean.match(/,/g)||[]).length, ';':(clean.match(/;/g)||[]).length, '\t':(clean.match(/\t/g)||[]).length };
  return Object.entries(sc).sort((a,b)=>b[1]-a[1])[0][0];
}

// Parsear lÃ­nea CSV respetando comillas
function parseLine(line, sep) {
  const result = [];
  let curr = '', inQ = false;
  // Quitar el '+' inicial si existe
  const cleaned = line.startsWith('+') ? line.slice(1) : line;
  for (let i = 0; i < cleaned.length; i++) {
    const c = cleaned[i];
    if (c === '"') { inQ = !inQ; continue; }
    if (c === sep && !inQ) { result.push(curr.trim()); curr = ''; continue; }
    curr += c;
  }
  result.push(curr.trim());
  return result;
}

const lines = raw.split(/\r?\n/).filter(l => l.trim() && !l.trim().startsWith('#'));
if (lines.length < 2) throw new Error(`GEO: CSV invÃ¡lido (${lines.length} lÃ­neas)`);

const sep = detectSep(lines[0]);

// Normalizar headers: quitar +, comillas, tildes, pasar a minÃºsculas
const rawHeaders = parseLine(lines[0], sep);
const headers = rawHeaders.map(h =>
  h.toLowerCase()
   .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
   .replace(/[^a-z0-9]/g, '_')
   .replace(/_+/g, '_')
   .replace(/^_|_$/g, '')
);

console.log('GEO_HEADERS_RAW:', JSON.stringify(rawHeaders));
console.log('GEO_HEADERS_NORM:', JSON.stringify(headers));

// Mapeo flexible de columnas normalizadas
function findCol(headers, ...candidates) {
  for (const c of candidates) {
    const idx = headers.indexOf(c);
    if (idx >= 0) return idx;
  }
  return -1;
}

const iMunicipio  = findCol(headers, 'municipio', 'nombre_municipio', 'nombre', 'localidad');
const iProvincia  = findCol(headers, 'provincia', 'nombre_provincia');
const iComunidad  = findCol(headers, 'comunidad', 'comunidad_autonoma', 'ccaa', 'nombre_comunidad');
const iPoblacion  = findCol(headers, 'poblacion', 'habitantes', 'poblaci_n');
const iLatitud    = findCol(headers, 'latitud', 'lat');
const iLongitud   = findCol(headers, 'longitud', 'lon', 'lng');

console.log('GEO_COL_IDX:', JSON.stringify({ municipio:iMunicipio, provincia:iProvincia, comunidad:iComunidad, lat:iLatitud, lon:iLongitud, pob:iPoblacion }));

if (iMunicipio < 0 || iProvincia < 0) throw new Error('GEO: No se encontraron columnas Municipio/Provincia en el CSV');

const valid = [], dead = [];

for (const line of lines.slice(1)) {
  if (!line.trim()) continue;
  const vals = parseLine(line, sep);

  const nombre    = iMunicipio >= 0 ? (vals[iMunicipio]||'').trim() : '';
  const provincia = iProvincia >= 0 ? (vals[iProvincia]||'').trim() : '';
  const comunidad = iComunidad >= 0 ? (vals[iComunidad]||'').trim() : '';
  const lat       = iLatitud   >= 0 ? parseNum(vals[iLatitud])  : null;
  const lon       = iLongitud  >= 0 ? parseNum(vals[iLongitud]) : null;
  const pob       = iPoblacion >= 0 ? parseInt2(vals[iPoblacion]) : null;

  if (!nombre || !provincia) { dead.push({ line, _error:'Falta nombre o provincia' }); continue; }

  valid.push({
    cod_ine: null,
    nombre_municipio: nombre,
    nombre_provincia: provincia,
    nombre_comunidad: comunidad || null,
    latitud:  lat,
    longitud: lon,
    slug:     slugify(nombre + '-' + provincia),
    poblacion: pob
  });
}

console.log(JSON.stringify({ stage:'GEO_PARSE_OK', total:lines.length-1, valid:valid.length, dead:dead.length }));
if (!valid.length) throw new Error('GEO: 0 municipios vÃ¡lidos â€“ revisa el CSV');

return valid.map(v => ({ json: { ...ctx, record: v } }));

// GEO - Upsert municipios_dataset_es en Supabase
const __helpers = (typeof this !== 'undefined' && this && this.helpers) ? this.helpers : null;
const __httpRequest = (__helpers && typeof __helpers.httpRequest === 'function')
  ? __helpers.httpRequest.bind(__helpers)
  : null;

async function _fetchPost(url, body, extraHeaders) {
  if (!__httpRequest) throw new Error('httpRequest helper not available in Code node runtime');
  return await __httpRequest({
    method: 'POST',
    url,
    headers: {
      'Content-Type': 'application/json',
      ...(extraHeaders || {}),
    },
    body,
    json: true,
  });
}

const ctx = $('INIT - Env & Config').first().json;
const items = $input.all();

if (!items.length) return [{ json: { ...ctx, stage: 'GEO_UPSERT_SKIP', count: 0 } }];
if (ctx.DRY_RUN) {
  console.log(JSON.stringify({ stage: 'GEO_UPSERT_DRYRUN', count: items.length }));
  return [{ json: { ...ctx, stage: 'GEO_UPSERT_DRYRUN', count: items.length } }];
}

const records = items.map(i => {
  const r = i.json.record || {};
  const lat = Number(r.latitud);
  const lon = Number(r.longitud);
  const pobl = Number(r.poblacion);

  return {
    municipio: String(r.nombre_municipio || '').trim(),
    provincia: String(r.nombre_provincia || '').trim(),
    comunidad_autonoma: String(r.nombre_comunidad || 'Desconocida').trim() || 'Desconocida',
    poblacion: Number.isFinite(pobl) ? Math.max(0, Math.round(pobl)) : 0,
    latitud: Number.isFinite(lat) ? lat : 0,
    longitud: Number.isFinite(lon) ? lon : 0,
    codigo_postal: '00000',
    slug: String(r.slug || '').trim(),
  };
}).filter(r => r.municipio && r.provincia && r.slug);

if (!records.length) {
  return [{ json: { ...ctx, stage: 'GEO_UPSERT_SKIP_EMPTY_NORMALIZED', count: 0 } }];
}

await _fetchPost(`${ctx.SUPABASE_URL}/rest/v1/municipios_dataset_es?on_conflict=slug`, records, {
  apikey: ctx.SUPABASE_SERVICE_ROLE_KEY,
  Authorization: `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json',
  Prefer: 'resolution=merge-duplicates,return=minimal',
});

console.log(JSON.stringify({ stage: 'GEO_UPSERT', batchSize: records.length }));
return [{ json: { ...ctx, stage: 'GEO_UPSERT_DONE', count: records.length } }];

// Ã¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢Â

const __helpers = (typeof this !== 'undefined' && this && this.helpers) ? this.helpers : null;
const __httpRequest = (__helpers && typeof __helpers.httpRequest === 'function')
  ? __helpers.httpRequest.bind(__helpers)
