// GEO - Upsert slugs_seo_municipios_espana_es
// Ã¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢Â
const ctx = $('INIT - Env & Config').first().json;
const items = $input.all();

if (!items.length) return [{ json: { ...ctx, stage: 'SLUGS_UPSERT_SKIP', count: 0 } }];
if (ctx.DRY_RUN) return [{ json: { ...ctx, stage: 'SLUGS_UPSERT_DRYRUN', count: 0 } }];

const slugRecords = items.map(i => ({
  slug: i.json.record.slug,
  municipio: i.json.record.nombre_municipio
}));

await _fetchPost(`${ctx.SUPABASE_URL}/rest/v1/slugs_seo_municipios_espana_es?on_conflict=slug`, slugRecords, {
    'apikey': ctx.SUPABASE_SERVICE_ROLE_KEY,
    'Authorization': `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json',
    'Prefer': 'resolution=merge-duplicates,return=minimal'
  });

console.log(JSON.stringify({ stage: 'SLUGS_UPSERT', count: slugRecords.length }));
return [{ json: { ...ctx, stage: 'SLUGS_UPSERT_DONE', count: slugRecords.length } }];

// Ã¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢Â
// PVGIS_ENRICH - Recuperar coords ÃƒÂºnicas de Supabase
// y enriquecer con radiaciÃƒÂ³n solar
// Ã¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢ÂÃ¢â€¢Â
const ctx = $('INIT - Env & Config').first().json;
console.log(JSON.stringify({ stage: 'PVGIS_START', runId: ctx.runId }));
return [{ json: { ...ctx, subflow: 'PVGIS_ENRICH' } }];

// PVGIS - Seleccionar 1 coordenada por provincia (determinista)
// Evita sobreescrituras aleatorias al hacer upsert por provincia
const ctx = $('INIT - Env & Config').first().json;
const inItems = $input.all();

const municipios = [];
const upstreamErrors = [];
for (const it of inItems) {
  const j = it.json;
  if (j && (j.error || j.message || j.code)) upstreamErrors.push(j);
  if (Array.isArray(j)) municipios.push(...j);
  else if (j && typeof j === 'object') municipios.push(j);
}

const byProvincia = new Map();
for (const m of municipios) {
  const provincia = String(m.provincia || '').trim();
  const latNum = Number(m.latitud);
  const lonNum = Number(m.longitud);
  if (!provincia || !Number.isFinite(latNum) || !Number.isFinite(lonNum)) continue;
  if (latNum === 0 || lonNum === 0) continue;

  // Conserva la primera coordenada valida por provincia para mantener estabilidad entre runs
  if (!byProvincia.has(provincia)) {
    byProvincia.set(provincia, {
      ...ctx,
      provincia,
      lat: latNum.toFixed(4),
      lon: lonNum.toFixed(4),
    });
  }
}

const unique = Array.from(byProvincia.values());

if (!unique.length) {
  console.warn(JSON.stringify({
    stage: 'PVGIS_DEDUPE_EMPTY',
    total: municipios.length,
    upstreamErrorCount: upstreamErrors.length,
    sampleUpstreamError: upstreamErrors[0] || null,
  }));
  return [{ json: { ...ctx, __pvgis_control: true, stage: 'PVGIS_DEDUPE_EMPTY' } }];
}

// Guardar mapa coord->provincia para recuperar provincia tras HTTP Request
let sds = {};
try {
  sds = $getWorkflowStaticData('global') || {};
} catch (_) {
  sds = {};
}
if (!sds.pvgisCoordMap) sds.pvgisCoordMap = {};
const runId = ctx.runId || `run_${Date.now()}`;
sds.pvgisCoordMap[runId] = {};
for (const u of unique) {
  sds.pvgisCoordMap[runId][`${u.lat}|${u.lon}`] = u.provincia;
}

console.log(JSON.stringify({
  stage: 'PVGIS_DEDUPE',
  total: municipios.length,
  selectedProvincias: unique.length,
  runId,
}));

return unique.map(u => ({ json: u }));

// PVGIS - Parsear respuesta y preparar upsert en radiacion_solar_provincial_es
const ctx = $('INIT - Env & Config').first().json;
const items = $input.all();
const results = [];

let sds = {};
try {
  sds = $getWorkflowStaticData('global') || {};
} catch (_) {
  sds = {};
}
const runId = ctx.runId || null;
const coordMap = (runId && sds.pvgisCoordMap && sds.pvgisCoordMap[runId]) ? sds.pvgisCoordMap[runId] : {};

for (const item of items) {
  try {
    const pvgisData = item.json || {};
    const outputs = pvgisData.outputs || {};
    const totals = outputs.totals || {};

    const latRaw = pvgisData?.inputs?.location?.latitude ?? pvgisData?.inputs?.lat ?? null;
    const lonRaw = pvgisData?.inputs?.location?.longitude ?? pvgisData?.inputs?.lon ?? null;

    const lat = Number(latRaw);
    const lon = Number(lonRaw);
    const key = (Number.isFinite(lat) && Number.isFinite(lon)) ? `${lat.toFixed(4)}|${lon.toFixed(4)}` : null;

    const provincia = (item.json && item.json.provincia) || (key ? coordMap[key] : null) || null;
    if (!provincia) {
      console.warn(JSON.stringify({ stage: 'PVGIS_PARSE_SKIP_NO_PROVINCIA', key, sample: pvgisData?.inputs || null }));
      continue;
    }

    const eYear = totals.fixed?.E_y || null;
    const hYear = totals.fixed?.H_i_opt || totals.fixed?.['H(i)_y'] || null;

    const record = {
      provincia,
      horas_sol_anuales: eYear ? Math.round(eYear) : 1800,
      irradiacion_kwh_m2: hYear ? Math.round(hYear * 10) / 10 : 1600.0,
      produccion_media_panel_1kw: eYear ? Math.round(eYear * 10) / 10 : 1400.0
    };

    if (!ctx.DRY_RUN) {
      results.push({ json: { ...ctx, record } });
    } else {
      console.log(JSON.stringify({ stage: 'PVGIS_DRYRUN', record }));
    }
  } catch (e) {
    console.error(JSON.stringify({ stage: 'PVGIS_PARSE_ERROR', error: e.message }));
  }
}

if (!results.length) {
  return [{ json: { ...ctx, __pvgis_control: true, stage: 'PVGIS_PARSE_EMPTY_BATCH' } }];
}

return results;

// PVGIS - Upsert radiacion_solar_provincial_es (resiliente ante 5xx)

const __helpers = (typeof this !== 'undefined' && this && this.helpers) ? this.helpers : null;
const __httpRequest = (__helpers && typeof __helpers.httpRequest === 'function')
  ? __helpers.httpRequest.bind(__helpers)
  : null;

async function _fetchPost(url, body, extraHeaders) {
  if (!__httpRequest) throw new Error('httpRequest helper not available in Code node runtime');
  return await __httpRequest({
    method: 'POST',
    url,
    headers: {
      'Content-Type': 'application/json',
      ...(extraHeaders || {}),
    },
    body,
    json: true,
  });
}

function errToJson(err) {
  return {
    message: String(err?.message || ''),
    description: String(err?.description || ''),
    statusCode: err?.statusCode || err?.response?.status || null,
    data: err?.response?.data || err?.error || null,
  };
}

function chunks(arr, size) {
  const out = [];
  for (let i = 0; i < arr.length; i += size) out.push(arr.slice(i, i + size));
  return out;
}

const ctx = $('INIT - Env & Config').first().json;
const items = $input.all();
let records = items.map(i => i.json?.record).filter(Boolean);

// Dedupe final por provincia para estabilidad y evitar choques innecesarios
const byProv = new Map();
for (const r of records) {
  const p = String(r.provincia || '').trim();
  if (!p) continue;
  if (!byProv.has(p)) byProv.set(p, r);
}
records = Array.from(byProv.values());

if (ctx.DRY_RUN) {
  return [{ json: { ...ctx, stage: 'PVGIS_UPSERT_DRYRUN', count: records.length } }];
}

if (!records.length) {
  return [{ json: { ...ctx, stage: 'PVGIS_UPSERT_SKIP', count: 0 } }];
}

const endpoint = `${ctx.SUPABASE_URL}/rest/v1/radiacion_solar_provincial_es?on_conflict=provincia`;
const headers = {
  apikey: ctx.SUPABASE_SERVICE_ROLE_KEY,
  Authorization: `Bearer ${ctx.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json',
  Prefer: 'resolution=merge-duplicates,return=minimal',
};

let successCount = 0;
let failCount = 0;
const errors = [];

try {
  await _fetchPost(endpoint, records, headers);
  successCount = records.length;
} catch (bulkErr) {
  errors.push({ scope: 'bulk', error: errToJson(bulkErr) });

  for (const batch of chunks(records, 20)) {
    try {
      await _fetchPost(endpoint, batch, headers);
      successCount += batch.length;
    } catch (batchErr) {
      for (const rec of batch) {
        try {
          await _fetchPost(endpoint, [rec], headers);
          successCount += 1;
        } catch (rowErr) {
          failCount += 1;
          if (errors.length < 10) {
            errors.push({
              scope: 'row',
              provincia: rec.provincia || null,
              payload: rec,
              error: errToJson(rowErr),
            });
          }
        }
      }
    }
  }
}

const stage = failCount > 0 ? 'PVGIS_UPSERT_SOFT_FAIL' : 'PVGIS_UPSERT_DONE';
console.log(JSON.stringify({
  stage,
  total: records.length,
  successCount,
  failCount,
  sampleErrors: errors.slice(0, 3),
}));

return [{
  json: {
    ...ctx,
    stage,
    count: successCount,
    failCount,
    total: records.length,
    errors: errors.slice(0, 5),
  },
}];

