async function callAiJson(promptText) {
  if (!ctx.AI_API_KEY) return [];
  try {
    const resp = await _http({
      method: 'POST',
      url: ctx.AI_BASE_URL,
      headers: {
        Authorization: 'Bearer ' + ctx.AI_API_KEY,
        'Content-Type': 'application/json',
      },
      body: {
        model: ctx.AI_MODEL,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: 'Devuelve JSON valido y compacto.' },
          { role: 'user', content: promptText },
        ],
      },
      json: true,
    });
    const content = resp?.choices?.[0]?.message?.content || '{}';
    const parsed = JSON.parse(content);
    return parsed.items || parsed.bonificaciones || [];
  } catch (e) {
    console.warn(JSON.stringify({ stage: 'BONIF_AI_ERROR', error: e.message }));
    return [];
  }
}

async function aiExtractFromSourceText(sourceText, sourceUrl) {
  if (!ctx.AI_API_KEY) return [];
