// ESIOS - Parsear respuesta de precios PVPC
const ctx = $('INIT - Env & Config').first().json;
const data = $input.first().json || {};

const values = Array.isArray(data.indicator?.values) ? data.indicator.values : [];

function toIsoDate(v) {
  if (!v) return null;
  const d = new Date(v);
  if (!Number.isFinite(d.getTime())) return null;
  return d.toISOString().slice(0, 10);
}

const fechaFromValue =
  toIsoDate(values[0]?.datetime_utc) ||
  toIsoDate(values[0]?.datetime) ||
  toIsoDate(values[0]?.datetime_local) ||
  null;

const fecha =
  fechaFromValue ||
  toIsoDate(data.indicator?.values?.[0]?.date) ||
  new Date().toISOString().slice(0, 10);

if (!values.length) {
  console.warn(JSON.stringify({ stage: 'ESIOS_EMPTY', fecha }));
  // Devuelve estimacion para no bloquear ramas downstream
  const record = {
    fecha,
    tarifa_codigo: 'pvpc_2_0td',
    precio_kwh_media: 0.15,
    precio_kwh_min: 0.12,
    precio_kwh_max: 0.22,
    fuente: 'fallback_estimado',
    indicador_id: String(data.indicator?.id || '1001'),
  };
  return [{ json: { ...ctx, record } }];
}

const precios = values
  .map(v => Number(v.value) / 1000)
  .filter(n => Number.isFinite(n));

if (!precios.length) {
  console.warn(JSON.stringify({ stage: 'ESIOS_VALUES_INVALID', fecha, total: values.length }));
  return [{ json: { ...ctx, record: {
    fecha,
    tarifa_codigo: 'pvpc_2_0td',
    precio_kwh_media: 0.15,
    precio_kwh_min: 0.12,
    precio_kwh_max: 0.22,
    fuente: 'fallback_sin_valores',
    indicador_id: String(data.indicator?.id || '1001'),
  } } }];
}

const precio_medio = precios.reduce((a, b) => a + b, 0) / precios.length;
const precio_min = Math.min(...precios);
const precio_max = Math.max(...precios);

const record = {
  fecha,
  tarifa_codigo: 'pvpc_2_0td',
  precio_kwh_media: Math.round(precio_medio * 100000) / 100000,
  precio_kwh_min: Math.round(precio_min * 100000) / 100000,
  precio_kwh_max: Math.round(precio_max * 100000) / 100000,
  fuente: 'esios',
  indicador_id: String(data.indicator?.id || '1001')
};

