    : 4.8;

  const consumo = [150, 250, 350, 450, 600, 800];
  const horas = [
    Math.max(3.5, Math.round((horasProm - 0.6) * 100) / 100),
    Math.max(3.8, Math.round((horasProm - 0.3) * 100) / 100),
    Math.max(4.2, Math.round(horasProm * 100) / 100),
