function errToJson(err) {
  return {
    message: String(err?.message || ''),
    description: String(err?.description || ''),
    statusCode: err?.statusCode || err?.response?.status || null,
    data: err?.response?.data || err?.error || null,
  };
}

async function post(urlPath, payload, allowFail = false) {
  try {
    await httpRequest({
      method: 'POST',
      url: ctx.SUPABASE_URL + '/rest/v1/' + urlPath,
      headers: {
        apikey: ctx.SUPABASE_SERVICE_ROLE_KEY,
        Authorization: 'Bearer ' + ctx.SUPABASE_SERVICE_ROLE_KEY,
        'Content-Type': 'application/json',
        Prefer: 'resolution=merge-duplicates,return=minimal',
      },
      body: payload,
      json: true,
    });
    return { ok: true };
  } catch (e) {
    const err = errToJson(e);
    if (!allowFail) throw e;
    return { ok: false, error: err };
  }
}

