const item = $input.first()?.json || {};
const ctx = $('INIT - Env & Config').first().json;
const store = $getWorkflowStaticData('global');

if (!store.branchSync) store.branchSync = {};

const runId = ctx.runId || item.runId || `run_${Date.now()}`;
if (!store.branchSync[runId]) {
  store.branchSync[runId] = {
    done: {},
    emitted: false,
    updatedAt: new Date().toISOString(),
  };
}

// PVGIS se ejecuta, pero no bloquea la finalizacion global.
const required = ['GEO', 'BONIF', 'COMPAT', 'ESIOS'];
const optional = ['PVGIS'];
const state = store.branchSync[runId];
const branch = item.__branchDone;

if (branch) state.done[branch] = true;
state.updatedAt = new Date().toISOString();

const missing = required.filter((b) => !state.done[b]);

if (state.emitted || missing.length > 0) {
  console.log(JSON.stringify({
    stage: 'SYNC_WAITING',
    runId,
    received: branch || null,
    done: Object.keys(state.done),
    missing,
    optionalPending: optional.filter((b) => !state.done[b]),
  }));
  return [];
}

state.emitted = true;
const optionalPending = optional.filter((b) => !state.done[b]);
const degraded = optionalPending.length > 0;
console.log(JSON.stringify({
  stage: degraded ? 'SYNC_READY_WITH_OPTIONAL_PENDING' : 'SYNC_READY',
  runId,
  done: Object.keys(state.done),
  optionalPending,
}));

return [{
  json: {
    ...ctx,
    runId,
    syncDone: Object.keys(state.done),
    syncOptionalPending: optionalPending,
    syncDegraded: degraded,
  },
}];
